import{_ as a,a as t,ai as i,o as l}from"./chunks/framework.Dc1yMVMM.js";const p=JSON.parse('{"title":"Agent","description":"","frontmatter":{},"headers":[],"relativePath":"ai/index.md","filePath":"ai/index.md","lastUpdated":1772787983000}'),o={name:"ai/index.md"};function r(n,e,d,s,h,c){return l(),t("div",null,e[0]||(e[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /grady/ai.md for this page in Markdown format</div><h1 id="agent" tabindex="-1">Agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;Agent&quot;">​</a></h1><h2 id="agent-工作原理" tabindex="-1">Agent 工作原理 <a class="header-anchor" href="#agent-工作原理" aria-label="Permalink to &quot;Agent 工作原理&quot;">​</a></h2><p>一个 Agent 由三个部分组成。</p><ol><li>Instruction（指令）。用于引导 agent 行为的 system prompt （系统提示词） 和 rules</li><li>Tools（工具）。文件编辑、代码库搜索、终端执行等</li><li>Prompt（提示词/用户消息。用户发出的提示词和后续补充，用于指挥具体工作</li></ol><h2 id="工具" tabindex="-1">工具 <a class="header-anchor" href="#工具" aria-label="Permalink to &quot;工具&quot;">​</a></h2><p>工具是构建 agent 的基础模块。</p><h2 id="聊天框里的工作原理" tabindex="-1">聊天框里的工作原理 <a class="header-anchor" href="#聊天框里的工作原理" aria-label="Permalink to &quot;聊天框里的工作原理&quot;">​</a></h2><ol><li>Agent 提出澄清性问题以理解你的需求</li><li>在你的代码中检索以收集相关上下文</li><li>创建一份完整的实现计划</li><li>你可以通过聊天或 Markdown 文件审阅并编辑该计划</li><li>准备好后点击构建该计划</li></ol><h2 id="插件" tabindex="-1">插件 <a class="header-anchor" href="#插件" aria-label="Permalink to &quot;插件&quot;">​</a></h2><p>插件会将 rules、skills、agents、commands、MCP servers 和 hooks 打包成可分发的 bundle，可在 Cursor IDE 中使用。你可以浏览社区开发的插件，或构建你自己的插件与其他开发者共享。</p><h3 id="插件包含的内容" tabindex="-1">插件包含的内容 <a class="header-anchor" href="#插件包含的内容" aria-label="Permalink to &quot;插件包含的内容&quot;">​</a></h3><blockquote><p>插件可以包含以下组件的任意组合：</p></blockquote><ul><li>Rules 持久化的 AI 指南和编码规范 (.mdc 文件)</li><li>Skills 处理复杂任务的专用 Agent 能力</li><li>Agents 自定义 Agent 配置和提示词</li><li>Commands Agent 可执行的命令文件</li><li>MCP Servers Model Context Protocol 集成</li><li>Hooks 由事件触发的自动化脚本</li></ul><p>示例在<code>example/mcp-server</code></p>',15)]))}const m=a(o,[["render",r]]);export{p as __pageData,m as default};
